SELECT

FROM
    rdp_user
WHERE
    parent_id = #{parentId}
and
    bind_account = #{bindAccount}
and
    bind_type = #{bindType,javaType=com.clougence.clouddm.console.web.dal.enumeration.AccountBindType}

SELECT

FROM
    rdp_user
WHERE
    parent_id = #{parentId}

        AND role_id=#{roleId}


        AND (
            (username LIKE CONCAT(#{prefix},'%') OR sub_account LIKE
            CONCAT(#{prefix},'%')) OR uid = #{prefix}
        )

order by gmt_create desc

SELECT

FROM
    rdp_user
WHERE
    phone = #{phone}
AND username = #{username}
AND email = #{email}
AND company = #{company}
AND account_type = 'PRIMARY_ACCOUNT'

